CREATE TABLE ad_account_connection ( id SERIAL PRIMARY KEY, user_id BIGINT NOT NULL, provider VARCHAR(50) NOT NULL, ad_account_id VARCHAR(64) NOT NULL,
ad_account_name VARCHAR(255), account_id VARCHAR(64), account_status INTEGER, currency VARCHAR(10), timezone_name VARCHAR(64),
business_id VARCHAR(64), active BOOLEAN NOT NULL DEFAULT FALSE, created_at TIMESTAMP NOT NULL DEFAULT NOW(), updated_at TIMESTAMP NOT NULL DEFAULT NOW(),
CONSTRAINT fk_ad_account_user FOREIGN KEY (user_id) REFERENCES USERS(ID), CONSTRAINT uq_user_provider_adaccount UNIQUE (user_id, provider, ad_account_id) );
CREATE INDEX idx_ad_account_user_id ON ad_account_connection(user_id); CREATE INDEX idx_ad_account_provider ON ad_account_connection(provider); CREATE INDEX idx_ad_account_active ON ad_account_connection(active);
